listitem.programlisting:
rabbitmq().
  consume {
    queue("user")
    connection {
      host = "localhost"
      port = 5672
      password = "Ceila1995"
      username = "PaulSmith"
    }
    concurrency(2)
    prefetchCount (11)
}

section.programlisting:
.rabbitmq()
.produce {
    connection {
      host = "localhost"
      port = 5672
      password = "Ceila1995"
      username = "PaulSmith"

    }
    records { _, input ->
        listOf(
            RabbitMqProducerRecord(
                exchange = "battery_state",
                routingKey = "battery_state",
                props = null,
                value = objectMapper.writeValueAsBytes(input)
            )
        )
    }
}
